function initPWA() {
    // Pre-baked icons (gold logo on dark, generated at build time)
    const icon192 = 'data:image/png;base64,';
    const icon512 = 'data:image/png;base64,';

    async function setup() {
        // Web app manifest
        const manifest = {
            name: 'YardHop',
            short_name: 'YardHop',
            description: 'Find Yard, Estate & Garage Sales Near You',
            start_url: '/',
            scope: '/',
            display: 'standalone',
            orientation: 'portrait',
            background_color: '#1a1714',
            theme_color: '#D4AF37',
            icons: [
                { src: icon192, sizes: '192x192', type: 'image/png', purpose: 'any maskable' },
                { src: icon512, sizes: '512x512', type: 'image/png', purpose: 'any maskable' }
            ]
        };
        const mBlob = new Blob([JSON.stringify(manifest)], { type: 'application/json' });
        const mLink = document.createElement('link');
        mLink.rel = 'manifest';
        mLink.href = URL.createObjectURL(mBlob);
        document.head.appendChild(mLink);

        // Service worker for offline caching + install eligibility
        if ('serviceWorker' in navigator) {
            navigator.serviceWorker.register('/sw.js', { scope: '/' }).catch(() => {});
        }
    }

    setup();
}

document.addEventListener('DOMContentLoaded', () => {
    initPWA();
    loadTheme();
    loadFavorites();
    loadUserData();
    loadListings().then(() => {
        updateCategoryCounts();
        renderFeaturedListings();
        renderNearbyListings();
        renderMapPins();
        renderNearbyPage();
        renderMapSidebar();
    });
    updateFavCount();
    // Theme toggle
    const themeToggle = document.getElementById('themeToggle');
    if (themeToggle)
        themeToggle.addEventListener('click', toggleTheme);
    // Hamburger
    const hamburger = document.getElementById('hamburger');
    if (hamburger)
        hamburger.addEventListener('click', toggleMobileMenu);
    // Drop zone
    setupDropZone();
    // Address autocomplete (Google Places takes over once Maps is ready)
    setupAddressAutocomplete();
    // Load Google Maps (only if a key is configured) and request user location
    loadGoogleMaps();
    requestUserLocation();
});

function loadTheme() {
    const saved = localStorage.getItem('yardhop-theme') || 'light';
    document.documentElement.setAttribute('data-theme', saved);
}
function toggleTheme() {
    const current = document.documentElement.getAttribute('data-theme');
    const next = current === 'dark' ? 'light' : 'dark';
    document.documentElement.setAttribute('data-theme', next);
    localStorage.setItem('yardhop-theme', next);
    applyMapTheme();
    renderMenuDrawer();
}
// ============================================================
// NAVIGATION
// ============================================================

function showPage(page) {
    // Hide all pages
    document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
    // Show target
    const target = document.getElementById(`page-${page}`);
    if (target)
        target.classList.add('active');
    // Update nav links
    document.querySelectorAll('.nav-link').forEach(l => l.classList.remove('active'));
    document.querySelectorAll('.bnav-item').forEach(b => {
        b.classList.remove('active');
        if (b.dataset.page === page)
            b.classList.add('active');
    });
    // Page-specific renders
    if (page === 'create')
        resetCreateForm();
    if (page === 'nearby')
        renderNearbyPage();
    if (page === 'favorites')
        renderFavoritesPage();
    if (page === 'map') {
        renderMapSidebar();
        if (mainMap) {
            google.maps.event.trigger(mainMap, 'resize');
            mainMap.setCenter(userLocation || DEFAULT_CENTER);
        }
    }
    // Scroll to top
    window.scrollTo({ top: 0, behavior: 'smooth' });
    // Close mobile menu
    closeMobileMenu();
}

function toggleMobileMenu() {
    openMenuDrawer();
}
function closeMobileMenu() {
    closeMenuDrawer();
}
function openMenuDrawer() {
    renderMenuDrawer();
    document.getElementById('menuDrawer').classList.add('open');
    document.getElementById('menuOverlay').classList.add('open');
    document.body.style.overflow = 'hidden';
}
function closeMenuDrawer() {
    document.getElementById('menuDrawer').classList.remove('open');
    document.getElementById('menuOverlay').classList.remove('open');
    document.body.style.overflow = '';
}

async function togglePushNotifications(enable) {
    if (!('Notification' in window)) return;
    if (enable) {
        const perm = await Notification.requestPermission();
        if (perm === 'granted') {
            localStorage.setItem('yardhop-push', 'on');
            showToast('Push notifications enabled');
        } else {
            localStorage.setItem('yardhop-push', 'off');
            const toggle = document.getElementById('pushToggle');
            if (toggle) toggle.checked = false;
            showToast('Permission denied — enable notifications in your browser settings');
        }
    } else {
        localStorage.setItem('yardhop-push', 'off');
        showToast('Push notifications disabled');
    }
}

// ============================================================
let toastTimeout;
function showToast(message) {
    const toast = document.getElementById('toast');
    if (!toast)
        return;
    toast.textContent = message;
    toast.classList.add('show');
    clearTimeout(toastTimeout);
    toastTimeout = setTimeout(() => toast.classList.remove('show'), 3000);
}

function requestUserLocation() {
    const cached = localStorage.getItem('yardhop-user-location');
    if (cached) {
        try {
            userLocation = JSON.parse(cached);
            recomputeDistances();
        } catch(e) {}
    }
    if (!('geolocation' in navigator)) return;
    navigator.geolocation.getCurrentPosition(
        pos => {
            userLocation = { lat: pos.coords.latitude, lng: pos.coords.longitude };
            localStorage.setItem('yardhop-user-location', JSON.stringify(userLocation));
            recomputeDistances();
            renderFeaturedListings();
            renderNearbyListings();
            renderNearbyPage();
            renderMapSidebar();
            addOrMoveUserMarker();
            if (nearbyMap) {
                nearbyMap.setCenter(userLocation);
                if (nearbyUserMarker) { nearbyUserMarker.setPosition(userLocation); }
                else { nearbyUserMarker = new google.maps.Marker({ position: userLocation, map: nearbyMap, title: 'You are here', zIndex: 9999, icon: userDot() }); }
            }
            if (homePreviewMap) {
                homePreviewMap.setCenter(userLocation);
                if (homeUserMarker) { homeUserMarker.setPosition(userLocation); }
                else { homeUserMarker = new google.maps.Marker({ position: userLocation, map: homePreviewMap, title: 'You are here', zIndex: 9999, icon: userDot() }); }
            }
            showToast('📍 Found you — sales sorted by distance');
        },
        err => {
            // Permission denied / unavailable / not a secure context: keep sample distances
            console.info('YardHop: location unavailable (' + err.message + ') — using sample distances.');
        },
        { enableHighAccuracy: true, timeout: 8000, maximumAge: 60000 }
    );
}

// Expose functions to window for HTML onclick attributes
